// 尝试使用 fetch 获取微信小程序开发文档页面
async function main() {
  try {
    const response = await fetch('https://developers.weixin.qq.com/miniprogram/dev/framework/', {
      headers: {
        'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36'
      }
    });
    console.log('Status:', response.status);
    console.log('URL:', response.url);

    if (response.ok) {
      const text = await response.text();
      // 提取标题和关键链接
      const titleMatch = text.match(/<title>(.*?)<\/title>/);
      console.log('Title:', titleMatch ? titleMatch[1] : 'Not found');

      // 提取一些链接
      const links = text.match(/href="(\/miniprogram\/dev\/[^"]+)"/g);
      if (links) {
        const uniqueLinks = [...new Set(links)].slice(0, 20);
        console.log('\nSome documentation links:');
        uniqueLinks.forEach(link => console.log('https://developers.weixin.qq.com' + link.match(/href="([^"]+)"/)[1]));
      }
    }
  } catch (e) {
    console.error('Error:', e.message);
  }
}
main();
"}
